package com.weib.entity;
import jakarta.persistence.*; import lombok.Data; import java.time.LocalDateTime;
@Entity @Table(name="forum_comments", indexes=@Index(name="idx_forum_comments_post_status_created",columnList="post_id,status,created_at")) @Data
public class ForumComment { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(name="post_id",nullable=false) private Long postId; @Column(name="author_id",nullable=false) private Long authorId; @Column(nullable=false,columnDefinition="TEXT") private String content; @Column(nullable=false,length=20) private String status="ACTIVE"; @Column(name="created_at",nullable=false,updatable=false) private LocalDateTime createdAt; @Column(name="updated_at",nullable=false) private LocalDateTime updatedAt; @PrePersist protected void onCreate(){LocalDateTime n=LocalDateTime.now();createdAt=n;updatedAt=n;} @PreUpdate protected void onUpdate(){updatedAt=LocalDateTime.now();} }
